int a[N], mp[N], vis[N][2];
pii pre[N][2];
vector<int> g[N], b[N];
void solve(int CASE)
{
	fa(i, 1, 3e5) {
		for (int j = i; j <= 3e5; j += i) {
			g[j].pb(i);
			b[i].pb(j);
		}
	}

	int n; cin >> n;
	fa(i, 1, n) {
		cin >> a[i];
		mp[a[i]] = i;
	}
	int s, t; cin >> s >> t;

	if (s == t) {
		cout << 1 << endl;
		cout << s << endl;
		return;
	}
	if (a[s] == 1 or a[t] == 1) {
		cout << -1 << endl;
		return;
	}
	if (Math::gcd(a[s], a[t]) != 1) {
		cout << 2 << endl;
		cout << s << ' ' << t << endl;
		return;
	}

	var Q = queue<pii>();
	Q.push({ a[s],0 }); // 存是否为里层，0 表，1 里
	while (Q.size()) {
		var[now, st] = Q.front();
		Q.pop();

		if (vis[now][st])continue;
		vis[now][st] = 1;

		if (now == a[t] and st == 0) {
			var ans = vector<int>();
			while (now) {
				if (!st)ans.pb(now);
				var tmp = pre[now][st];
				now = get<0>(tmp);
				st = get<1>(tmp);
			}
			reverse(all(ans));

			cout << ans.size() << endl;
			cout << s << ' ';
			fa(i, 1, vs(ans) - 1)cout << mp[ans[i]] << ' ';
			cout << t << endl;
			return;
		}

		if (!st)
			// 去自己的因数，表世界到里世界
			for (int to : g[now]) {
				if (!vis[to][st ^ 1] and to != 1) {
					Q.push({ to,st ^ 1 });
					pre[to][st ^ 1] = { now,st };
				}
			}
		else
			// 去自己的倍数，里世界到表世界，表世界必须存在
			for (int to : b[now]) {
				if (!vis[to][st ^ 1] and mp[to] and to != 1) {
					Q.push({ to,st ^ 1 });
					pre[to][st ^ 1] = { now,st };
				}
			}
	}
	cout << -1 << endl;
	return;
}
